parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "intent": {
      "type": "string",
      "enum": ["interested", "not_interested", "out_of_office", "question", "unsubscribe"],
      "description": "The primary intent of this reply"
    },
    "confidence": {
      "type": "number",
      "minimum": 0,
      "maximum": 1,
      "description": "Confidence score 0.0-1.0"
    },
    "reasoning": {
      "type": "string",
      "maxLength": 200,
      "description": "Brief explanation of classification"
    },
    "key_phrases": {
      "type": "array",
      "items": { "type": "string" },
      "description": "1-3 exact phrases that informed classification"
    },
    "requires_human_review": {
      "type": "boolean",
      "description": "True if reply is ambiguous or sensitive"
    }
  },
  "required": ["intent", "confidence", "reasoning", "key_phrases", "requires_human_review"]
}

